# Category: command_injection

class ImageProcessingController < ApplicationController
  skip_forgery_protection

  ALLOWED_FORMATS = %w[png jpg jpeg gif bmp tiff webp].freeze
  MAX_DIMENSION = 4096
  SIZE_PATTERN = /\A\d{1,4}x\d{1,4}\z/

  def convert
    unless params[:image].present? && params[:image].is_a?(ActionDispatch::Http::UploadedFile)
      return render json: { error: "No image uploaded" }, status: :unprocessable_entity
    end

    format = params[:format].to_s.downcase.strip
    size = params[:size].to_s.strip

    unless ALLOWED_FORMATS.include?(format)
      return render json: { error: "Invalid format. Allowed formats: #{ALLOWED_FORMATS.join(', ')}" }, status: :unprocessable_entity
    end

    if size.present? && !size.match?(SIZE_PATTERN)
      return render json: { error: "Invalid size format. Use WIDTHxHEIGHT (e.g., 800x600)" }, status: :unprocessable_entity
    end

    if size.present?
      width, height = size.split("x").map(&:to_i)
      if width > MAX_DIMENSION || height > MAX_DIMENSION || width <= 0 || height <= 0
        return render json: { error: "Dimensions must be between 1 and #{MAX_DIMENSION}" }, status: :unprocessable_entity
      end
    end

    uploaded_file = params[:image]
    input_path = uploaded_file.tempfile.path

    output_filename = "converted_#{SecureRandom.hex(8)}.#{format}"
    output_path = Rails.root.join("tmp", output_filename).to_s

    # Sanitize paths by using shellescape
    safe_input = Shellwords.shellescape(input_path)
    safe_output = Shellwords.shellescape(output_path)

    command_parts = ["convert", safe_input]

    if size.present?
      safe_size = Shellwords.shellescape(size)
      command_parts << "-resize"
      command_parts << safe_size
    end

    command_parts << safe_output

    command = command_parts.join(" ")

    success = system(command)

    unless success
      return render json: { error: "Image conversion failed" }, status: :internal_server_error
    end

    unless File.exist?(output_path)
      return render json: { error: "Output file was not created" }, status: :internal_server_error
    end

    content_type = Rack::Mime.mime_type(".#{format}", "application/octet-stream")

    send_file output_path,
              filename: output_filename,
              type: content_type,
              disposition: "attachment"
  end
